import { WorkflowRuntime } from 'mastra/workflows';
import { countTokens } from 'vex_dev/sdk';

const tokenMonitor = async (ctx: WorkflowRuntime.Context) => {
  const currentContext = ctx.state.conversationHistory + ctx.state.lastToolOutput;
  const tokenCount = await countTokens(currentContext);

  if (tokenCount > 120000) {
    console.error(`⚠️ Context overflow: ${tokenCount} tokens`);
    throw new Error('Context window exceeded safe limit');
  }

  return ctx;
};

// Add to Mastra workflow
workflow.useMiddleware(tokenMonitor);

import { AgentRuntime } from 'mastra/agents';
import { semanticSimilarity } from 'vex_dev/sdk';

const memoryValidator = async (ctx: AgentRuntime.Context) => {
  const retrievedMemory = await ctx.agentMemory.retrieve(ctx.sessionId, 10);
  const currentQueryTokens = await countTokens(ctx.userMessage);

  for (const memoryItem of retrievedMemory) {
    const relevance = await semanticSimilarity(ctx.userMessage, memoryItem.content);
    if (relevance < 0.3 || (Date.now() - memoryItem.timestamp) > 24 * 60 * 60 * 1000) {
      console.warn('🗑️ Stale/irrelevant memory filtered:', memoryItem.id);
      ctx.state.filteredMemory.push(memoryItem);
    }
  }

  ctx.state.memoryContext = retrievedMemory.filter(item => !ctx.state.filteredMemory.includes(item));
  return ctx;
};

import { ToolRuntime } from 'mastra/tools';

const toolSizeChecker = async (toolResult: ToolRuntime.Result) => {
  const resultTokens = await countTokens(JSON.stringify(toolResult.output));

  if (resultTokens > 8000) {
    console.error(`🛑 Tool output too large: ${resultTokens} tokens`);
    toolResult.output = {
      summary: await summarizeContent(toolResult.output),
      truncated: true,
      originalSize: resultTokens
    };
  }

  return toolResult;
};

// Register with Mastra tools
toolRegistry.usePostProcessor(toolSizeChecker);

