import { WorkflowRuntime } from 'mastra/workflows';
import { summarize, prioritizeContext } from 'vex_dev/sdk';

const contextTruncator = async (ctx: WorkflowRuntime.Context) => {
  const fullContext = ctx.state.getFullContext();
  const tokenCount = await countTokens(fullContext);

  if (tokenCount > 110000) {
    // Prioritize recent + relevant context
    const prioritized = await prioritizeContext(fullContext, ctx.userMessage);
    const summary = await summarize(prioritized, { maxTokens: 2000 });

    ctx.state.contextPayload = {
      activeContext: prioritized.slice(0, 80000),
      summary,
      truncationInfo: `Reduced from ${tokenCount} to ${await countTokens(ctx.state.contextPayload)} tokens`
    };
  }

  return ctx;
};

workflow.useMiddleware(contextTruncator);

import { AgentRuntime } from 'mastra/agents';

const smartMemoryFilter = async (ctx: AgentRuntime.Context) => {
  const allMemory = await ctx.agentMemory.retrieve(ctx.sessionId, 50);
  const filteredMemory = allMemory
    .filter(memory => {
      const ageHours = (Date.now() - memory.timestamp) / (1000 * 60 * 60);
      const relevance = semanticSimilarity(ctx.userMessage, memory.content);
      return ageHours < 24 && relevance > 0.4;
    })
    .slice(0, 15) // Max 15 recent relevant memories
    .sort((a, b) => b.timestamp - a.timestamp);

  ctx.state.relevantMemory = filteredMemory;
  console.log(`📦 Memory filtered: ${allMemory.length} → ${filteredMemory.length}`);

  return ctx;
};

import { ToolRuntime } from 'mastra/tools';

const toolCompressor = async (toolResult: ToolRuntime.Result) => {
  if (await countTokens(JSON.stringify(toolResult.output)) > 4000) {
    const compressed = await compressToolOutput(toolResult.output);

    toolResult.output = {
      $schema: 'vex/tool-compressed',
      summary: compressed.summary,
      keyFacts: compressed.facts,
      dataShape: analyzeDataShape(toolResult.output),
      rawSize: await countTokens(JSON.stringify(toolResult.output)),
      compressedSize: await countTokens(JSON.stringify(compressed))
    };
  }

  return toolResult;
};

function compressToolOutput(rawOutput: any) {
  return {
    summary: `Key insights from ${Object.keys(rawOutput).length} records`,
    facts: extractKeyFacts(rawOutput),
    stats: computeDataStats(rawOutput)
  };
}

